enum CoppedBackendError: LocalizedError {
    case receiptNotFound
    case receiptAlreadyUsed
    case invalidReceipt
    case clipNotFound
    case invalidDuration

    var errorDescription: String? {
        switch self {
        case .receiptNotFound:
            return "Receipt not found. Try scanning a valid creator receipt QR."
        case .receiptAlreadyUsed:
            return "You already created a clip for this receipt."
        case .invalidReceipt:
            return "This receipt is invalid for Copped."
        case .clipNotFound:
            return "Clip not found."
        case .invalidDuration:
            return "Video must be between 5 and 15 seconds."
        }
    }
}

extension Date {
    nonisolated func coppedRelativeDescription(reference: Date = Date()) -> String {
        let formatter = RelativeDateTimeFormatter()
        formatter.unitsStyle = .abbreviated
        return formatter.localizedString(for: self, relativeTo: reference)
    }
}

extension Int {
    nonisolated var coppedCurrencyDisplay: String {
        String(format: "$%.2f", Double(self) / 100.0)
    }
}

// MARK: - From Submissions/copped/CoppedRemoteBackend.swift

import Foundation

enum CoppedRemoteBackendError: LocalizedError {
    case network(URLError)
    case requestFailed(statusCode: Int, message: String)
    case invalidResponse(String)

    var isConnectivityIssue: Bool {
        switch self {
        case .network(let error):
            switch error.code {
            case .cannotFindHost,
                 .cannotConnectToHost,
                 .dnsLookupFailed,
                 .networkConnectionLost,
                 .notConnectedToInternet,
                 .timedOut:
                return true
            default:
                return false
            }
        case .requestFailed, .invalidResponse:
            return false
        }
    }

    var errorDescription: String? {
        switch self {
        case .network(let error):
            return error.localizedDescription
        case .requestFailed(_, let message):
            return message
        case .invalidResponse(let message):
            return message
        }
    }
}

enum CoppedRemoteBackend {
    nonisolated static let defaultAPIBaseURL = URL(string: "https://clipstakes.skilled5041.workers.dev")!

    private static let session: URLSession = {
        let configuration = URLSessionConfiguration.ephemeral
        configuration.timeoutIntervalForRequest = 15
        configuration.timeoutIntervalForResource = 25
        return URLSession(configuration: configuration)
    }()

    nonisolated static func resolveAPIBaseURL(override: String?) -> URL {
        if let override, let url = normalizedURL(from: override) {
            return url
        }

        if let persisted = UserDefaults.standard.string(forKey: "copped.api_base_url"),
           let url = normalizedURL(from: persisted) {
            return url
        }

        return defaultAPIBaseURL
    }

    nonisolated static func fallbackWalletPassURL(apiBaseURL: URL, walletCode: String) -> URL {
        apiBaseURL
            .appendingPathComponent("wallet")
            .appendingPathComponent(walletCode)
            .appendingPathComponent("pass")
    }

    static func getReceipt(
        receiptId: String,
        apiBaseURL: URL,
        deviceID: String
    ) async throws -> CoppedReceipt {
        do {
            let response = try await requestJSON(
                apiBaseURL: apiBaseURL,
                paths: ["/receipt/\(receiptId)"],
                method: "GET",
                deviceID: deviceID,
                body: nil
            )
            let payload = payloadDict(from: response)

            let productIDs = productIDsFromReceiptPayload(payload)
            let clipCreated = boolValue(for: ["clip_created", "clipCreated"], in: payload) ?? false
            let createdAt = dateValue(for: ["created_at", "createdAt"], in: payload) ?? Date()

            guard !productIDs.isEmpty else {
                throw CoppedRemoteBackendError.invalidResponse("Receipt response did not include product IDs.")
            }

            return CoppedReceipt(
                id: receiptId,
                productIDs: productIDs,
                clipCreated: clipCreated,
                createdAt: createdAt
            )
        } catch let error as CoppedRemoteBackendError {
            if case .requestFailed(let statusCode, _) = error {
                if statusCode == 404 { throw CoppedBackendError.receiptNotFound }
                if statusCode == 409 || statusCode == 422 { throw CoppedBackendError.receiptAlreadyUsed }
            }
            throw error
        }
    }

    static func createUploadURL(
        receiptId: String,
        productId: String,
        apiBaseURL: URL,
        deviceID: String
    ) async throws -> CoppedUploadURLResponse {
        let requestBody: [String: Any] = [
            "receipt_id": receiptId,
            "product_id": productId
        ]

        let response = try await requestJSON(
            apiBaseURL: apiBaseURL,
            paths: ["/upload", "/upload-url"],
            method: "POST",
            deviceID: deviceID,
            body: requestBody
        )

        let payload = payloadDict(from: response)
        guard let uploadURLString = stringValue(for: ["upload_url", "uploadURL"], in: payload),
              let videoURLString = stringValue(for: ["video_url", "videoURL"], in: payload),
              let uploadURL = makeURL(from: uploadURLString, apiBaseURL: apiBaseURL),
              let videoURL = makeURL(from: videoURLString, apiBaseURL: apiBaseURL)
        else {
            throw CoppedRemoteBackendError.invalidResponse("Upload response missing upload_url or video_url.")
        }

        let key = stringValue(for: ["key"], in: payload)
            ?? videoURL.path.trimmingCharacters(in: CharacterSet(charactersIn: "/"))

        return CoppedUploadURLResponse(
            uploadURL: uploadURL,
            videoURL: videoURL,
            key: key
        )
    }

    static func createClip(
        receiptId: String,
        deviceID: String,
        productId: String,
        videoURL: URL,
        textOverlay: String?,
        textPosition: CoppedTextPosition,
        durationSeconds: Int,
        apiBaseURL: URL
    ) async throws -> CoppedCreateClipResponse {
        var requestBody: [String: Any] = [
            "receipt_id": receiptId,
            "product_id": productId,
            "video_url": videoURL.absoluteString,
            "text_position": textPosition.rawValue,
            "duration_seconds": durationSeconds
        ]
        if let textOverlay, !textOverlay.isEmpty {
            requestBody["text_overlay"] = textOverlay
        }

        do {
            let response = try await requestJSON(
                apiBaseURL: apiBaseURL,
                paths: ["/clips"],
                method: "POST",
                deviceID: deviceID,
                body: requestBody
            )
            let payload = payloadDict(from: response)
            let wallet = dictValue(for: ["wallet"], in: payload) ?? [:]
            let reward = dictValue(for: ["reward"], in: payload) ?? [:]
            let balances = dictValue(for: ["balances", "totals"], in: payload) ?? [:]

            let clipID = stringValue(for: ["clip_id", "clipId", "id"], in: payload)
                ?? UUID().uuidString.lowercased()

            guard let walletCode = stringValue(
                for: ["code", "wallet_code", "walletCode", "coupon_code", "couponCode"],
                in: wallet,
                fallback: payload
            ) else {
                throw CoppedRemoteBackendError.invalidResponse("Clip response missing wallet code.")
            }

            let backendPassURL = urlValue(
                for: ["pass_url", "wallet_pass_url", "passURL", "url"],
                in: wallet,
                apiBaseURL: apiBaseURL
            ) ?? urlValue(
                for: ["pass_url", "wallet_pass_url", "passURL"],
                in: payload,
                apiBaseURL: apiBaseURL
            )

            let passURL = backendPassURL ?? fallbackWalletPassURL(apiBaseURL: apiBaseURL, walletCode: walletCode)

            let instantCreditCents = intValue(
                for: ["instant_credit_cents", "instantCreditCents", "credited_cents", "creditedCents"],
                in: reward,
                fallback: payload
            ) ?? 0

            let availableBalanceCents = intValue(
                for: ["available_cents", "available_balance_cents", "availableBalanceCents", "balance_cents", "balanceCents"],
                in: balances,
                fallback: payload
            ) ?? 0

            let message = stringValue(for: ["message"], in: payload)
                ?? "Clip created."

            return CoppedCreateClipResponse(
                clipID: clipID,
                walletCode: walletCode,
                instantCreditCents: instantCreditCents,
                instantCreditDisplay: instantCreditCents.coppedCurrencyDisplay,
                passURL: passURL,
                availableBalanceCents: availableBalanceCents,
                availableBalanceDisplay: availableBalanceCents.coppedCurrencyDisplay,
                message: message
            )
        } catch let error as CoppedRemoteBackendError {
            if case .requestFailed(let statusCode, _) = error, statusCode == 409 {
                throw CoppedBackendError.receiptAlreadyUsed
            }
            throw error
        }
    }

    static func getRewards(
        deviceID: String,
        apiBaseURL: URL
    ) async throws -> CoppedRewardsSnapshot {
        let response = try await requestJSON(
            apiBaseURL: apiBaseURL,
            paths: ["/rewards/me"],
            method: "GET",
            deviceID: deviceID,
            body: nil
        )

        let payload = payloadDict(from: response)
        let wallet = dictValue(for: ["wallet"], in: payload) ?? payload
        let balances = dictValue(for: ["balances", "totals"], in: payload) ?? [:]

        guard let walletCode = stringValue(
            for: ["code", "wallet_code", "walletCode", "coupon_code", "couponCode"],
            in: wallet,
            fallback: payload
        ) else {
            throw CoppedRemoteBackendError.invalidResponse("Rewards response missing wallet code.")
        }

        let passURL = urlValue(
            for: ["pass_url", "wallet_pass_url", "passURL", "url"],
            in: wallet,
            apiBaseURL: apiBaseURL
        ) ?? urlValue(
            for: ["pass_url", "wallet_pass_url", "passURL"],
            in: payload,
            apiBaseURL: apiBaseURL
        ) ?? fallbackWalletPassURL(apiBaseURL: apiBaseURL, walletCode: walletCode)

        let availableBalanceCents = intValue(
            for: ["available_cents", "available_balance_cents", "availableBalanceCents", "balance_cents", "balanceCents"],
            in: balances,
            fallback: wallet
        ) ?? intValue(
            for: ["available_cents", "available_balance_cents", "availableBalanceCents", "balance_cents", "balanceCents"],
            in: wallet,
            fallback: payload
        ) ?? 0

        let lifetimeEarnedCents = intValue(
            for: ["lifetime_earned_cents", "lifetimeEarnedCents"],
            in: balances,
            fallback: wallet
        ) ?? intValue(
            for: ["lifetime_earned_cents", "lifetimeEarnedCents"],
            in: wallet,
            fallback: payload
        ) ?? availableBalanceCents

        let transactions = parseTransactions(
            from: arrayValue(for: ["transactions"], in: payload)
                ?? arrayValue(for: ["transactions"], in: wallet)
                ?? []
        )

        return CoppedRewardsSnapshot(
            walletCode: walletCode,
            passURL: passURL,
            availableBalanceCents: availableBalanceCents,
            availableBalanceDisplay: availableBalanceCents.coppedCurrencyDisplay,
            lifetimeEarnedCents: lifetimeEarnedCents,
            lifetimeEarnedDisplay: lifetimeEarnedCents.coppedCurrencyDisplay,
            transactions: transactions
        )
    }

    static func getClips(
        productId: String,
        apiBaseURL: URL,
        deviceID: String
    ) async throws -> [CoppedClip] {
        let response = try await requestJSON(
            apiBaseURL: apiBaseURL,
            paths: ["/clips/\(productId)"],
            method: "GET",
            deviceID: deviceID,
            body: nil
        )

        let payload = payloadDict(from: response)
        let rawClips = arrayValue(for: ["clips", "items", "data"], in: payload)
            ?? arrayValue(for: ["clips", "items", "data"], in: response)
            ?? []

        let parsed = rawClips.compactMap { parseClip(from: $0, fallbackProductId: productId, apiBaseURL: apiBaseURL) }
        return parsed
            .filter(\.isActive)
            .sorted {
                if $0.conversions == $1.conversions {
                    return $0.createdAt > $1.createdAt
                }
                return $0.conversions > $1.conversions
            }
    }

    static func performCheckout(
        productId: String,
        clipId: String?,
        apiBaseURL: URL,
        deviceID: String
    ) async throws -> CoppedCheckoutOutcome {
        var requestBody: [String: Any] = [
            "product_id": productId
        ]
        if let clipId, !clipId.isEmpty {
            requestBody["clip_id"] = clipId
        }

        let response = try await requestJSON(
            apiBaseURL: apiBaseURL,
            paths: ["/checkout/dev"],
            method: "POST",
            deviceID: deviceID,
            body: requestBody
        )

        let payload = payloadDict(from: response)
        guard let orderID = stringValue(for: ["order_id", "orderId"], in: payload),
              let receiptID = stringValue(for: ["receipt_id", "receiptId"], in: payload) else {
            throw CoppedRemoteBackendError.invalidResponse("Checkout response missing order_id or receipt_id.")
        }

        let conversion = dictValue(for: ["conversion"], in: payload).flatMap(parseConversionResponse(from:))

        return CoppedCheckoutOutcome(
            orderID: orderID,
            receiptID: receiptID,
            conversion: conversion
        )
    }

    // MARK: - Networking

    private static func requestJSON(
        apiBaseURL: URL,
        paths: [String],
        method: String,
        deviceID: String,
        body: [String: Any]?
    ) async throws -> [String: Any] {
        var lastError: Error?

        for path in paths {
            do {
                return try await requestJSON(
                    apiBaseURL: apiBaseURL,
                    path: path,
                    method: method,
                    deviceID: deviceID,
                    body: body
                )
            } catch let error as CoppedRemoteBackendError {
                lastError = error
                if case .requestFailed(let statusCode, _) = error, statusCode == 404 {
                    continue
                }
                throw error
            } catch {
                lastError = error
                throw error
            }
        }

        throw (lastError as? CoppedRemoteBackendError)
            ?? CoppedRemoteBackendError.invalidResponse("No valid backend endpoint found.")
    }

    private static func requestJSON(
        apiBaseURL: URL,
        path: String,
        method: String,
        deviceID: String,
        body: [String: Any]?
    ) async throws -> [String: Any] {
        let url = urlForPath(path, apiBaseURL: apiBaseURL)
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.setValue(deviceID, forHTTPHeaderField: "X-Device-ID")

        if let body {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
            request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        }

        do {
            let (data, response) = try await session.data(for: request)
            guard let httpResponse = response as? HTTPURLResponse else {
                throw CoppedRemoteBackendError.invalidResponse("Backend returned a non-HTTP response.")
            }

            let object = try jsonObject(from: data)
            if (200 ... 299).contains(httpResponse.statusCode) {
                return object
            }

            let payload = payloadDict(from: object)
            let message = stringValue(for: ["message", "error", "detail"], in: payload)
                ?? stringValue(for: ["message", "error", "detail"], in: object)
                ?? HTTPURLResponse.localizedString(forStatusCode: httpResponse.statusCode)

            throw CoppedRemoteBackendError.requestFailed(
                statusCode: httpResponse.statusCode,
                message: message
            )
        } catch let error as URLError {
            throw CoppedRemoteBackendError.network(error)
        } catch let error as CoppedRemoteBackendError {
            throw error
        } catch {
            throw CoppedRemoteBackendError.invalidResponse(error.localizedDescription)
        }
    }

    // MARK: - Parsing

    private static func parseTransactions(from raw: [[String: Any]]) -> [CoppedRewardTransaction] {
        raw.compactMap { item in
            let amount = intValue(for: ["amount_cents", "amountCents", "amount"], in: item) ?? 0
            let kindRaw = stringValue(for: ["kind", "type", "event"], in: item)?.lowercased() ?? ""
            let kind: CoppedRewardTransaction.Kind = kindRaw.contains("conversion") ? .conversion : .clipPublished

            return CoppedRewardTransaction(
                id: stringValue(for: ["id"], in: item) ?? UUID().uuidString.lowercased(),
                kind: kind,
                amountCents: amount,
                amountDisplay: amount.coppedCurrencyDisplay,
                clipID: stringValue(for: ["clip_id", "clipId"], in: item) ?? "",
                orderID: stringValue(for: ["order_id", "orderId"], in: item),
                createdAt: dateValue(for: ["created_at", "createdAt"], in: item) ?? Date()
            )
        }
    }

    private static func parseConversionResponse(from raw: [String: Any]) -> CoppedConversionResponse {
        let reward = dictValue(for: ["reward"], in: raw) ?? [:]
        let balances = dictValue(for: ["balances", "totals"], in: raw) ?? [:]
        let push = dictValue(for: ["push"], in: raw) ?? [:]

        let creditedCents = intValue(
            for: ["credited_cents", "creditedCents", "earnings_added", "reward_cents", "rewardCents"],
            in: raw,
            fallback: reward
        ) ?? 0

        let availableBalanceCents = intValue(
            for: ["available_balance_cents", "availableBalanceCents", "available_cents", "balance_cents", "balanceCents"],
            in: raw,
            fallback: balances
        ) ?? 0

        let pushSent = boolValue(for: ["push_sent", "pushSent", "sent"], in: raw)
            ?? boolValue(for: ["push_sent", "pushSent", "sent"], in: push)
            ?? false

        let withinPushWindow = boolValue(for: ["within_push_window", "withinPushWindow", "within_window", "withinWindow"], in: raw)
            ?? boolValue(for: ["within_push_window", "withinPushWindow", "within_window", "withinWindow"], in: push)
            ?? false

        let success = boolValue(for: ["success", "attributed", "reward_credited", "rewardCredited"], in: raw)
            ?? (creditedCents > 0)

        let creditedDisplay = stringValue(
            for: ["credited_display", "creditedDisplay", "display"],
            in: raw,
            fallback: reward
        ) ?? creditedCents.coppedCurrencyDisplay

        let availableBalanceDisplay = stringValue(
            for: ["available_balance_display", "availableBalanceDisplay", "available_display", "availableDisplay", "balance_display", "balanceDisplay"],
            in: raw,
            fallback: balances
        ) ?? availableBalanceCents.coppedCurrencyDisplay

        return CoppedConversionResponse(
            success: success,
            creditedCents: creditedCents,
            creditedDisplay: creditedDisplay,
            availableBalanceCents: availableBalanceCents,
            availableBalanceDisplay: availableBalanceDisplay,
            pushSent: pushSent,
            withinPushWindow: withinPushWindow
        )
    }

    private static func parseClip(
        from raw: [String: Any],
        fallbackProductId: String,
        apiBaseURL: URL
    ) -> CoppedClip? {
        let clipID = stringValue(for: ["id", "clip_id", "clipId"], in: raw) ?? UUID().uuidString.lowercased()

        let productDict = dictValue(for: ["product"], in: raw)
        let nestedVideo = dictValue(for: ["video"], in: raw)
        let nestedWallet = dictValue(for: ["wallet"], in: raw)
        let nestedOverlay = dictValue(for: ["overlay"], in: raw)
            ?? dictValue(for: ["caption"], in: raw)
            ?? dictValue(for: ["text"], in: raw)

        let productID = stringValue(for: ["product_id", "productId"], in: raw)
            ?? stringValue(for: ["id", "product_id", "productId"], in: productDict ?? [:])
            ?? fallbackProductId

        let videoURL = urlValue(for: ["video_url", "videoURL", "url"], in: raw, apiBaseURL: apiBaseURL)
            ?? urlValue(for: ["url", "video_url", "videoURL"], in: nestedVideo ?? [:], apiBaseURL: apiBaseURL)
            ?? urlValue(for: ["playback_url", "playbackURL"], in: raw, apiBaseURL: apiBaseURL)
        guard let videoURL else { return nil }

        let textOverlay = stringValue(
            for: ["text_overlay", "textOverlay", "caption", "text", "overlay_text", "overlayText"],
            in: raw
        ) ?? stringValue(
            for: ["text_overlay", "textOverlay", "caption", "text", "overlay_text", "overlayText"],
            in: nestedOverlay ?? [:]
        )
        let textPositionRaw = stringValue(for: ["text_position", "textPosition"], in: raw)?.lowercased()
        let textPosition = CoppedTextPosition(rawValue: textPositionRaw ?? "") ?? .bottom

        let durationSeconds = intValue(
            for: ["duration_seconds", "durationSeconds", "duration"],
            in: raw
        ) ?? 10

        let couponCode = stringValue(
            for: ["coupon_code", "couponCode", "wallet_code", "walletCode"],
            in: raw
        ) ?? stringValue(
            for: ["code", "wallet_code", "walletCode"],
            in: nestedWallet ?? [:]
        ) ?? "COP-UNKNOWN"

        let createdAt = dateValue(for: ["created_at", "createdAt"], in: raw) ?? Date()
        let expiresAt = dateValue(for: ["expires_at", "expiresAt"], in: raw)
            ?? createdAt.addingTimeInterval(365 * 24 * 60 * 60)

        return CoppedClip(
            id: clipID,
            receiptID: stringValue(for: ["receipt_id", "receiptId", "order_id", "orderId"], in: raw) ?? "remote-receipt",
            creatorDeviceID: stringValue(for: ["creator_device_id", "creatorDeviceId", "device_id", "deviceId"], in: raw) ?? "remote-device",
            productID: productID,
            videoURL: videoURL,
            textOverlay: textOverlay,
            textPosition: textPosition,
            durationSeconds: max(1, min(120, durationSeconds)),
            couponCode: couponCode,
            couponRedeemed: boolValue(for: ["coupon_redeemed", "couponRedeemed", "redeemed"], in: raw) ?? false,
            conversions: intValue(for: ["conversions", "conversion_count", "conversionCount"], in: raw) ?? 0,
            bonusCouponCode: stringValue(for: ["bonus_coupon_code", "bonusCouponCode"], in: raw),
            bonusPushed: boolValue(for: ["bonus_pushed", "bonusPushed"], in: raw) ?? false,
            bonusRedeemed: boolValue(for: ["bonus_redeemed", "bonusRedeemed"], in: raw) ?? false,
            isActive: boolValue(for: ["is_active", "isActive"], in: raw) ?? true,
            createdAt: createdAt,
            expiresAt: expiresAt
        )
    }

    private static func productIDsFromReceiptPayload(_ payload: [String: Any]) -> [String] {
        if let ids = stringArrayValue(for: ["product_ids", "productIds"], in: payload), !ids.isEmpty {
            return ids
        }

        if let products = arrayValue(for: ["products"], in: payload) {
            let ids = products.compactMap { stringValue(for: ["id", "product_id", "productId"], in: $0) }
            if !ids.isEmpty { return ids }
        }

        if let items = arrayValue(for: ["items", "line_items", "lineItems"], in: payload) {
            let ids = items.compactMap { stringValue(for: ["product_id", "productId", "id"], in: $0) }
            if !ids.isEmpty { return ids }
        }

        return []
    }

    private static func payloadDict(from object: [String: Any]) -> [String: Any] {
        if let data = object["data"] as? [String: Any] {
            return data
        }
        return object
    }

    private static func jsonObject(from data: Data) throws -> [String: Any] {
        guard !data.isEmpty else { return [:] }
        let json = try JSONSerialization.jsonObject(with: data)
        if let dict = json as? [String: Any] {
            return dict
        }
        if let array = json as? [[String: Any]] {
            return ["items": array]
        }
        return [:]
    }

    private static func urlForPath(_ path: String, apiBaseURL: URL) -> URL {
        if let absolute = URL(string: path), absolute.scheme != nil {
            return absolute
        }
        let trimmed = path.hasPrefix("/") ? String(path.dropFirst()) : path
        return apiBaseURL.appendingPathComponent(trimmed)
    }

    private static func makeURL(from raw: String, apiBaseURL: URL) -> URL? {
        if let absolute = URL(string: raw), absolute.scheme != nil {
            return absolute
        }
        return urlForPath(raw, apiBaseURL: apiBaseURL)
    }

    private nonisolated static func normalizedURL(from raw: String) -> URL? {
        let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty, let parsed = URL(string: trimmed),
              let scheme = parsed.scheme?.lowercased(),
              scheme == "https" || scheme == "http" else {
            return nil
        }

        let path = parsed.path.trimmingCharacters(in: CharacterSet(charactersIn: "/"))
        if path.isEmpty { return parsed }

        var components = URLComponents(url: parsed, resolvingAgainstBaseURL: false)
        components?.path = "/\(path)"
        return components?.url ?? parsed
    }

    private static func value(for keys: [String], in object: [String: Any]) -> Any? {
        for key in keys {
            if let value = object[key] {
                return value
            }
        }
        return nil
    }

    private static func dictValue(for keys: [String], in object: [String: Any]) -> [String: Any]? {
        value(for: keys, in: object) as? [String: Any]
    }

    private static func arrayValue(for keys: [String], in object: [String: Any]) -> [[String: Any]]? {
        guard let raw = value(for: keys, in: object) as? [Any] else { return nil }
        return raw.compactMap { $0 as? [String: Any] }
    }

    private static func stringArrayValue(for keys: [String], in object: [String: Any]) -> [String]? {
        guard let raw = value(for: keys, in: object) as? [Any] else { return nil }
        let values = raw.compactMap { item -> String? in
            if let string = item as? String { return string }
            if let number = item as? NSNumber { return number.stringValue }
            return nil
        }
        return values.isEmpty ? nil : values
    }

    private static func stringValue(
        for keys: [String],
        in object: [String: Any],
        fallback: [String: Any]? = nil
    ) -> String? {
        if let value = value(for: keys, in: object) {
            if let string = value as? String { return string }
            if let number = value as? NSNumber { return number.stringValue }
        }

        if let fallback {
            return stringValue(for: keys, in: fallback)
        }

        return nil
    }

    private static func intValue(
        for keys: [String],
        in object: [String: Any],
        fallback: [String: Any]? = nil
    ) -> Int? {
        if let value = value(for: keys, in: object) {
            if let integer = value as? Int { return integer }
            if let number = value as? NSNumber { return number.intValue }
            if let string = value as? String { return Int(string) }
        }

        if let fallback {
            return intValue(for: keys, in: fallback)
        }

        return nil
    }

    private static func boolValue(for keys: [String], in object: [String: Any]) -> Bool? {
        if let value = value(for: keys, in: object) {
            if let bool = value as? Bool { return bool }
            if let number = value as? NSNumber { return number.boolValue }
            if let string = value as? String {
                switch string.lowercased() {
                case "true", "1", "yes":
                    return true
                case "false", "0", "no":
                    return false
                default:
                    return nil
                }
            }
        }
        return nil
    }

    private static func urlValue(for keys: [String], in object: [String: Any], apiBaseURL: URL) -> URL? {
        guard let raw = stringValue(for: keys, in: object) else { return nil }
        return makeURL(from: raw, apiBaseURL: apiBaseURL)
    }

    private static func dateValue(for keys: [String], in object: [String: Any]) -> Date? {
        guard let raw = value(for: keys, in: object) else { return nil }

        if let timestamp = raw as? TimeInterval {
            return Date(timeIntervalSince1970: timestamp)
        }
        if let number = raw as? NSNumber {
            return Date(timeIntervalSince1970: number.doubleValue)
        }
        if let string = raw as? String {
            if let seconds = TimeInterval(string) {
                return Date(timeIntervalSince1970: seconds)
            }

            let isoFormatter = ISO8601DateFormatter()
            isoFormatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
            if let date = isoFormatter.date(from: string) {
                return date
            }

            let plainFormatter = ISO8601DateFormatter()
            if let date = plainFormatter.date(from: string) {
                return date
            }
        }

        return nil
    }
}

// MARK: - From Submissions/copped/CoppedShopifyPublicCatalogService.swift

import Foundation

enum CoppedShopifyPublicConfig {
    // Optional default store. Set this if you want public catalog loading without URL query params.
    // Example: "your-store.myshopify.com"
    static let defaultStoreDomain: String? = nil
    static let productsLimit = 250
}

enum CoppedCatalogSource {
    case shopifyPublic
    case fallback
}

struct CoppedCatalogLoadResult {
    let products: [CoppedProduct]
    let source: CoppedCatalogSource
    let storeDomain: String?
    let message: String?
}

actor CoppedShopifyPublicCatalogService {
    static let shared = CoppedShopifyPublicCatalogService()

    private var cachedProductsByDomain: [String: [CoppedProduct]] = [:]

    func loadCatalog(storeDomainOverride: String?) async -> CoppedCatalogLoadResult {
        let resolvedDomain = normalizeStoreDomain(storeDomainOverride)
            ?? normalizeStoreDomain(CoppedShopifyPublicConfig.defaultStoreDomain)

        guard let resolvedDomain else {
            let fallback = CoppedCatalog.fallbackProducts
            CoppedCatalog.updatePublicProducts(fallback)
            await CoppedMockBackend.shared.prepareDemoCatalog(with: fallback)
            return CoppedCatalogLoadResult(
                products: fallback,
                source: .fallback,
                storeDomain: nil,
                message: "Using fallback catalog. Add ?store=<domain> to load public Shopify products.json."
            )
        }

        if let cached = cachedProductsByDomain[resolvedDomain], !cached.isEmpty {
            CoppedCatalog.updatePublicProducts(cached)
            await CoppedMockBackend.shared.prepareDemoCatalog(with: cached)
            return CoppedCatalogLoadResult(
                products: cached,
                source: .shopifyPublic,
                storeDomain: resolvedDomain,
                message: nil
            )
        }

        do {
            let products = try await fetchProducts(domain: resolvedDomain)
            let mapped = mapProducts(products)

            guard !mapped.isEmpty else {
                throw CatalogError.emptyCatalog
            }

            cachedProductsByDomain[resolvedDomain] = mapped
            CoppedCatalog.updatePublicProducts(mapped)
            await CoppedMockBackend.shared.prepareDemoCatalog(with: mapped)

            return CoppedCatalogLoadResult(
                products: mapped,
                source: .shopifyPublic,
                storeDomain: resolvedDomain,
                message: "Loaded \(mapped.count) public products from \(resolvedDomain)."
            )
        } catch {
            let fallback = CoppedCatalog.fallbackProducts
            CoppedCatalog.updatePublicProducts(fallback)
            await CoppedMockBackend.shared.prepareDemoCatalog(with: fallback)

            return CoppedCatalogLoadResult(
                products: fallback,
                source: .fallback,
                storeDomain: resolvedDomain,
                message: "Public catalog failed (\(error.localizedDescription)). Using fallback products."
            )
        }
    }

    // MARK: - Private

    private func fetchProducts(domain: String) async throws -> [ShopifyProduct] {
        var components = URLComponents()
        components.scheme = "https"
        components.host = domain
        components.path = "/products.json"
        components.queryItems = [
            URLQueryItem(name: "limit", value: String(CoppedShopifyPublicConfig.productsLimit))
        ]

        guard let url = components.url else {
            throw CatalogError.invalidURL
        }

        let (data, response) = try await URLSession.shared.data(from: url)

        guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw CatalogError.badResponse
        }

        let decoded = try JSONDecoder().decode(ShopifyProductsResponse.self, from: data)
        return decoded.products
    }

    private func mapProducts(_ products: [ShopifyProduct]) -> [CoppedProduct] {
        products.compactMap { product in
            guard let id = product.id else { return nil }
            let rawPrice = product.variants.first?.price ?? "0"
            let numeric = Double(rawPrice.replacingOccurrences(of: ",", with: "")) ?? 0
            let image = product.image?.src ?? product.images.first?.src

            return CoppedProduct(
                id: String(id),
                name: product.title ?? "Product \(id)",
                price: numeric,
                systemImage: symbol(for: product.title ?? ""),
                imageURL: image.flatMap(URL.init(string:))
            )
        }
    }

    private func symbol(for title: String) -> String {
        let lower = title.lowercased()
        if lower.contains("hoodie") || lower.contains("shirt") || lower.contains("tee") {
            return "tshirt.fill"
        }
        if lower.contains("hat") || lower.contains("cap") {
            return "baseballcap.fill"
        }
        if lower.contains("vinyl") || lower.contains("cd") || lower.contains("album") {
            return "opticaldisc.fill"
        }
        if lower.contains("poster") || lower.contains("print") {
            return "photo.artframe"
        }
        return "shippingbox.fill"
    }

    private func normalizeStoreDomain(_ value: String?) -> String? {
        guard var value = value?.trimmingCharacters(in: .whitespacesAndNewlines), !value.isEmpty else {
            return nil
        }

        if value.contains("://"),
           let components = URLComponents(string: value),
           let host = components.host,
           !host.isEmpty {
            value = host
        }

        if value.hasPrefix("www.") {
            value = String(value.dropFirst(4))
        }

        guard value.contains(".") else { return nil }
        return value.lowercased()
    }
}

private enum CatalogError: LocalizedError {
    case invalidURL
    case badResponse
    case emptyCatalog

    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid public products URL"
        case .badResponse:
            return "Public products endpoint returned non-200 response"
        case .emptyCatalog:
            return "No products found in public catalog"
        }
    }
}

private struct ShopifyProductsResponse: Decodable {
    let products: [ShopifyProduct]
}

private struct ShopifyProduct: Decodable {
    let id: Int64?
    let title: String?
    let image: ShopifyImage?
    let images: [ShopifyImage]
    let variants: [ShopifyVariant]
}

private struct ShopifyImage: Decodable {
    let src: String?
}

private struct ShopifyVariant: Decodable {
    let price: String?
}

// MARK: - From Submissions/copped/CoppedUI/Components/Alert.swift

import SwiftUI

// MARK: - AlertButtonVM

public struct AlertButtonVM: ComponentVM {
  public var title: String = ""
  public var animationScale: AnimationScale = .medium
  public var color: ComponentColor?
  public var cornerRadius: ComponentRadius = .medium
  public var style: ButtonStyle = .filled
  public init() {}
}

// MARK: - AlertVM

public struct AlertVM: ComponentVM {
  public var title: String?
  public var message: String?
  public var primaryButton: AlertButtonVM?
  public var secondaryButton: AlertButtonVM?
  public var backgroundColor: UniversalColor?
  public var borderWidth: BorderWidth = .small
  public var closesOnOverlayTap: Bool = false
  public var contentPaddings: Paddings = .init(padding: 16)
  public var cornerRadius: ContainerRadius = .medium
  public var overlayStyle: ModalOverlayStyle = .dimmed
  public var transition: ModalTransition = .fast
  public init() {}
}

extension AlertVM {
  var modalVM: CenterModalVM {
    CenterModalVM {
      $0.backgroundColor = self.backgroundColor
      $0.borderWidth = self.borderWidth
      $0.closesOnOverlayTap = self.closesOnOverlayTap
      $0.contentPaddings = self.contentPaddings
      $0.cornerRadius = self.cornerRadius
      $0.overlayStyle = self.overlayStyle
      $0.transition = self.transition
      $0.size = .small
    }
  }

  var primaryButtonVM: ButtonVM? {
    let vm = primaryButton.map(mapAlertButtonVM)
    return secondaryButton.isNotNil ? vm : (vm ?? Self.defaultButtonVM)
  }

  var secondaryButtonVM: ButtonVM? {
    secondaryButton.map(mapAlertButtonVM)
  }

  private func mapAlertButtonVM(_ model: AlertButtonVM) -> ButtonVM {
    ButtonVM {
      $0.title = model.title
      $0.animationScale = model.animationScale
      $0.color = model.color
      $0.cornerRadius = model.cornerRadius
      $0.style = model.style
      $0.isFullWidth = true
    }
  }

  static let buttonsSpacing: CGFloat = 12

  static let defaultButtonVM = ButtonVM {
    $0.title = "OK"
    $0.color = .primary
    $0.style = .filled
    $0.isFullWidth = true
  }
}

// MARK: - AlertButtonsOrientationCalculator

struct AlertButtonsOrientationCalculator {
  enum Orientation { case vertical, horizontal }

  static func preferredOrientation(model: AlertVM) -> Orientation {
    guard let primary = model.primaryButtonVM,
          let secondary = model.secondaryButtonVM else {
      return .vertical
    }
    // Heuristic: short titles → horizontal
    let threshold = 14
    return (primary.title.count <= threshold && secondary.title.count <= threshold)
      ? .horizontal : .vertical
  }
}

// MARK: - AlertContent (internal)

struct AlertContent: View {
  @Binding var isPresented: Bool
  let model: AlertVM
  let primaryAction: (() -> Void)?
  let secondaryAction: (() -> Void)?

  var body: some View {
    SUCenterModal(
      isVisible: $isPresented,
      model: model.modalVM,
      header: {
        if model.message.isNotNil, let text = model.title { titleView(text) }
      },
      body: {
        if let text = model.message { messageView(text) }
        else if let text = model.title { titleView(text) }
      },
      footer: {
        switch AlertButtonsOrientationCalculator.preferredOrientation(model: model) {
        case .horizontal:
          HStack(spacing: AlertVM.buttonsSpacing) {
            buttonView(model: model.secondaryButtonVM, action: secondaryAction)
            buttonView(model: model.primaryButtonVM, action: primaryAction)
          }
        case .vertical:
          VStack(spacing: AlertVM.buttonsSpacing) {
            buttonView(model: model.primaryButtonVM, action: primaryAction)
            buttonView(model: model.secondaryButtonVM, action: secondaryAction)
          }
        }
      }
    )
  }

  private func titleView(_ text: String) -> some View {
    Text(text)
      .font(UniversalFont.mdHeadline.font)
      .foregroundStyle(UniversalColor.foreground.color)
      .multilineTextAlignment(.center)
      .frame(maxWidth: .infinity)
      .fixedSize(horizontal: false, vertical: true)
  }

  private func messageView(_ text: String) -> some View {
    Text(text)
      .font(UniversalFont.mdBody.font)
      .foregroundStyle(UniversalColor.secondaryForeground.color)
      .multilineTextAlignment(.center)
      .frame(maxWidth: .infinity)
  }

  @ViewBuilder
  private func buttonView(model: ButtonVM?, action: (() -> Void)?) -> some View {
    if let model {
      SUButton(model: model) {
        action?()
        isPresented = false
      }
    }
  }
}

// MARK: - View Extensions

extension View {
  public func suAlert(
    isPresented: Binding<Bool>,
    model: AlertVM,
    primaryAction: (() -> Void)? = nil,
    secondaryAction: (() -> Void)? = nil,
    onDismiss: (() -> Void)? = nil
  ) -> some View {
    self.modal(
      isVisible: isPresented,
      transitionDuration: model.transition.value,
      onDismiss: onDismiss
    ) {
      AlertContent(
        isPresented: isPresented,
        model: model,
        primaryAction: primaryAction,
        secondaryAction: secondaryAction
      )
    }
  }

  public func suAlert<Item: Identifiable>(
    item: Binding<Item?>,
    model: @escaping (Item) -> AlertVM,
    primaryAction: ((Item) -> Void)? = nil,
    secondaryAction: ((Item) -> Void)? = nil,
    onDismiss: (() -> Void)? = nil
  ) -> some View {
    self.modal(
      item: item,
      transitionDuration: { model($0).transition.value },
      onDismiss: onDismiss
    ) { unwrapped in
      AlertContent(
        isPresented: .init(
          get: { item.wrappedValue.isNotNil },
          set: { if $0 { item.wrappedValue = unwrapped } else { item.wrappedValue = nil } }
        ),
        model: model(unwrapped),
        primaryAction: { primaryAction?(unwrapped) },
        secondaryAction: { secondaryAction?(unwrapped) }
      )
    }
  }
}

// MARK: - From Submissions/copped/CoppedUI/Components/Button.swift

import SwiftUI

// MARK: - ButtonVM

public struct ButtonVM: ComponentVM {
  public var animationScale: AnimationScale = .medium
  public var color: ComponentColor?
  public var contentSpacing: CGFloat = 8.0
  public var cornerRadius: ComponentRadius = .medium
  public var font: UniversalFont?
  public var image: UniversalImage?
  public var imageLocation: ImageLocation = .leading
  @available(*, deprecated, message: "Use image.withRenderingMode(_:) instead.")
  public var imageRenderingMode: ImageRenderingMode?
  @available(*, deprecated, message: "Use image instead.")
  public var imageSrc: ImageSource?
  public var isEnabled: Bool = true
  public var isFullWidth: Bool = false
  public var isLoading: Bool = false
  public var loadingVM: LoadingVM?
  public var size: ComponentSize = .medium
  public var style: ButtonStyle = .filled
  public var title: String = ""
  public init() {}
}

// MARK: - ButtonVM.ImageLocation

extension ButtonVM {
  public enum ImageLocation {
    case leading, trailing
  }
}

// MARK: - ButtonVM.ImageSource (deprecated)

extension ButtonVM {
  public enum ImageSource: Hashable {
    case sfSymbol(String)
    case local(String, bundle: Bundle? = nil)
  }
}

// MARK: - ButtonVM Shared Helpers

extension ButtonVM {
  var isInteractive: Bool { isEnabled && !isLoading }

  var preferredLoadingVM: LoadingVM {
    return loadingVM ?? LoadingVM {
      $0.color = ComponentColor(
        main:     foregroundColor,
        contrast: self.color?.main ?? .background
      )
      $0.size = .small
    }
  }

  var backgroundColor: UniversalColor? {
    switch style {
    case .filled:
      return (color?.main ?? .content2).enabled(isInteractive)
    case .light:
      return (color?.background ?? .content1).enabled(isInteractive)
    case .plain, .bordered, .minimal, .glass:
      return nil
    }
  }

  var foregroundColor: UniversalColor {
    let c: UniversalColor = switch style {
    case .filled:
      color?.contrast ?? .foreground
    case .plain, .light, .bordered, .minimal, .glass:
      color?.main ?? .foreground
    }
    return c.enabled(isInteractive)
  }

  var borderWidth: CGFloat {
    switch style {
    case .filled, .plain, .light, .minimal, .glass: return 0.0
    case .bordered(let bw): return bw.value
    }
  }

  var borderColor: UniversalColor? {
    switch style {
    case .filled, .plain, .light, .minimal, .glass: return nil
    case .bordered:
      return (color?.main ?? .divider).enabled(isInteractive)
    }
  }

  var isGlassStyle: Bool { style == .glass }

  var glassAccentColor: Color? {
    color?.main.color
  }

  var preferredFont: UniversalFont {
    if let font { return font }
    switch size {
    case .small:  return .smButton
    case .medium: return .mdButton
    case .large:  return .lgButton
    }
  }

  var height: CGFloat? {
    switch style {
    case .minimal: return nil
    case .light, .filled, .bordered, .plain, .glass:
      return switch size {
      case .small:  36
      case .medium: 44
      case .large:  52
      }
    }
  }

  var imageSide: CGFloat {
    switch size {
    case .small:  20
    case .medium: 24
    case .large:  28
    }
  }

  var horizontalPadding: CGFloat {
    switch style {
    case .minimal: return 0
    case .light, .filled, .bordered, .plain, .glass:
      if title.isNotEmpty || isLoading {
        return switch size {
        case .small:  16
        case .medium: 20
        case .large:  24
        }
      } else {
        return switch size {
        case .small:  8
        case .medium: 10
        case .large:  12
        }
      }
    }
  }

  var width: CGFloat? { isFullWidth ? 10_000 : nil }

  var imageWithLegacyFallback: UniversalImage? {
    if let image { return image }
    guard let imageSrc else { return nil }
    let img: UniversalImage? = switch imageSrc {
    case .sfSymbol(let name):          UniversalImage(systemName: name)
    case .local(let name, let bundle): UniversalImage(name, bundle: bundle)
    }
    if let imageRenderingMode, let img {
      return img.withRenderingMode(imageRenderingMode)
    }
    return img
  }
}

// MARK: - SUButton

public struct SUButton: View {
  public var model: ButtonVM
  public var action: () -> Void
  public var onLongPress: (() -> Void)?
  @State public var scale: CGFloat = 1.0

  public init(model: ButtonVM, onLongPress: (() -> Void)? = nil, action: @escaping () -> Void = {}) {
    self.model = model
    self.onLongPress = onLongPress
    self.action = action
  }

  public var body: some View {
    Button(action: action) {
      HStack(spacing: model.contentSpacing) {
        content
      }
    }
    .buttonStyle(CKButtonStyle(model: model))
    .simultaneousGesture(
      DragGesture(minimumDistance: 0.0)
        .onChanged { _ in scale = model.animationScale.value }
        .onEnded   { _ in scale = 1.0 }
    )
    .disabled(!model.isInteractive)
    .modifier(OptionalLongPressModifier(action: onLongPress))
    .scaleEffect(scale, anchor: .center)
    .animation(.easeOut(duration: 0.05), value: scale)
  }

  @ViewBuilder
  private var content: some View {
    switch (model.isLoading, model.imageWithLegacyFallback, model.imageLocation) {
    case (true, _, _) where model.title.isEmpty:
      SULoading(model: model.preferredLoadingVM)
    case (true, _, _):
      SULoading(model: model.preferredLoadingVM)
      Text(model.title)
    case (false, let img?, _) where model.title.isEmpty:
      CKButtonImage(universalImage: img, tintColor: model.foregroundColor, side: model.imageSide)
    case (false, let img?, .leading):
      CKButtonImage(universalImage: img, tintColor: model.foregroundColor, side: model.imageSide)
      Text(model.title)
    case (false, let img?, .trailing):
      Text(model.title)
      CKButtonImage(universalImage: img, tintColor: model.foregroundColor, side: model.imageSide)
    case (false, _, _):
      Text(model.title)
    }
  }
}

// MARK: - Private Helpers

private struct CKButtonImage: View {
  let universalImage: UniversalImage
  let tintColor: UniversalColor
  let side: CGFloat

  var body: some View {
    universalImage.image
      .resizable()
      .scaledToFit()
      .tint(tintColor.color)
      .frame(width: side, height: side)
  }
}

private struct OptionalLongPressModifier: ViewModifier {
  let action: (() -> Void)?

  func body(content: Content) -> some View {
    if let action {
      content.onLongPressGesture(minimumDuration: 0.5, perform: action)
    } else {
      content
    }
  }
}

private struct CKButtonStyle: SwiftUI.ButtonStyle {
  let model: ButtonVM

  func makeBody(configuration: Configuration) -> some View {
    let label = configuration.label
      .font(model.preferredFont.font)
      .lineLimit(1)
      .padding(.horizontal, model.horizontalPadding)
      .frame(maxWidth: model.width)
      .frame(height: model.height)
      .contentShape(.rect)
      .foregroundStyle(model.foregroundColor.color)

    if model.isGlassStyle {
      label.liquidGlass(
        enabled: true,
        cornerRadius: model.cornerRadius.value(),
        accentColor: model.glassAccentColor
      )
    } else {
      label
        .background(model.backgroundColor?.color ?? .clear)
        .clipShape(RoundedRectangle(cornerRadius: model.cornerRadius.value()))
        .overlay {
          RoundedRectangle(cornerRadius: model.cornerRadius.value())
            .strokeBorder(model.borderColor?.color ?? .clear, lineWidth: model.borderWidth)
        }
    }
  }
}

// MARK: - From Submissions/copped/CoppedUI/Components/ExpandableCard.swift

import SwiftUI

// MARK: - ExpandableCard

/// A glass-effect card that expands from a compact preview to a full detail view.
/// Uses matched geometry + spring animation for a fluid expand/collapse.
public struct ExpandableCard<Preview: View, Detail: View>: View {
  @Binding var isExpanded: Bool
  let preview: () -> Preview
  let detail: () -> Detail
  var onExpandChange: ((Bool) -> Void)?

  /// Corner radius for collapsed state.
  var cornerRadius: CGFloat = 24
  /// Background blur style.
  var blurStyle: UIBlurEffect.Style = Theme.current.layout.glass.blurStyle
  /// Background tint on top of blur.
  var tint: Color = Theme.current.layout.glass.tint
  /// Border color.
  var borderColor: Color = Theme.current.layout.glass.border
  /// Border width.
  var borderWidth: CGFloat = Theme.current.layout.glass.borderWidth
  /// Collapsed card height. `nil` lets the preview size naturally.
  var collapsedHeight: CGFloat? = nil
  var useLiquidGlass: Bool = false

  public init(
    isExpanded: Binding<Bool>,
    cornerRadius: CGFloat = 24,
    blurStyle: UIBlurEffect.Style = Theme.current.layout.glass.blurStyle,
    tint: Color = Theme.current.layout.glass.tint,
    borderColor: Color = Theme.current.layout.glass.border,
    borderWidth: CGFloat = Theme.current.layout.glass.borderWidth,
    collapsedHeight: CGFloat? = nil,
    useLiquidGlass: Bool = false,
    onExpandChange: ((Bool) -> Void)? = nil,
    @ViewBuilder preview: @escaping () -> Preview,
    @ViewBuilder detail: @escaping () -> Detail
  ) {
    self._isExpanded = isExpanded
    self.cornerRadius = cornerRadius
    self.blurStyle = blurStyle
    self.tint = tint
    self.borderColor = borderColor
    self.borderWidth = borderWidth
    self.collapsedHeight = collapsedHeight
    self.useLiquidGlass = useLiquidGlass
    self.onExpandChange = onExpandChange
    self.preview = preview
    self.detail = detail
  }

  public var body: some View {
    VStack(spacing: 0) {
      // Preview is always visible
      preview()
        .frame(height: collapsedHeight)
        .frame(maxWidth: .infinity)
        .clipped()

      // Detail slides in when expanded
      if isExpanded {
        detail()
          .transition(.move(edge: .bottom).combined(with: .opacity))
      }
    }
    .liquidGlass(
      enabled: useLiquidGlass,
      cornerRadius: cornerRadius,
      blurStyle: blurStyle,
      tint: tint,
      borderColor: borderColor,
      borderWidth: borderWidth
    )
    .shadow(
      color: Theme.current.layout.glass.shadowColor,
      radius: Theme.current.layout.glass.shadowRadius,
      x: Theme.current.layout.glass.shadowOffset.width,
      y: Theme.current.layout.glass.shadowOffset.height
    )
    .onTapGesture {
      let newValue = !isExpanded
      onExpandChange?(newValue)
      withAnimation(Theme.current.layout.motion.smooth.animation) {
        isExpanded.toggle()
      }
    }
    .animation(Theme.current.layout.motion.smooth.animation, value: isExpanded)
  }
}

// MARK: - GlassCard

/// Standalone frosted-glass card. Use directly when you don't need expand/collapse.
public struct GlassCard<Content: View>: View {
  let content: () -> Content
  var cornerRadius: CGFloat = 24
  var blurStyle: UIBlurEffect.Style = Theme.current.layout.glass.blurStyle
  var tint: Color = Theme.current.layout.glass.tint
  var borderColor: Color = Theme.current.layout.glass.border
  var borderWidth: CGFloat = Theme.current.layout.glass.borderWidth

  var useLiquidGlass: Bool = false

  public init(
    cornerRadius: CGFloat = 24,
    blurStyle: UIBlurEffect.Style = Theme.current.layout.glass.blurStyle,
    tint: Color = Theme.current.layout.glass.tint,
    borderColor: Color = Theme.current.layout.glass.border,
    borderWidth: CGFloat = Theme.current.layout.glass.borderWidth,
    useLiquidGlass: Bool = false,
    @ViewBuilder content: @escaping () -> Content
  ) {
    self.cornerRadius = cornerRadius
    self.blurStyle = blurStyle
    self.tint = tint
    self.borderColor = borderColor
    self.borderWidth = borderWidth
    self.useLiquidGlass = useLiquidGlass
    self.content = content
  }

  public var body: some View {
    content()
      .liquidGlass(
        enabled: useLiquidGlass,
        cornerRadius: cornerRadius,
        blurStyle: blurStyle,
        tint: tint,
        borderColor: borderColor,
        borderWidth: borderWidth
      )
  }
}

// MARK: - GlassBackground

/// UIKit blur view wrapped for SwiftUI.
public struct GlassBackground: UIViewRepresentable {
  let style: UIBlurEffect.Style
  let tint: Color
  let cornerRadius: CGFloat

  public init(
    style: UIBlurEffect.Style = Theme.current.layout.glass.blurStyle,
    tint: Color = Theme.current.layout.glass.tint,
    cornerRadius: CGFloat = 20
  ) {
    self.style = style
    self.tint = tint
    self.cornerRadius = cornerRadius
  }

  public func makeUIView(context: Context) -> UIVisualEffectView {
    let view = UIVisualEffectView(effect: UIBlurEffect(style: style))
    view.clipsToBounds = true
    view.layer.cornerRadius = cornerRadius
    view.layer.cornerCurve = .continuous

    // Tint overlay
    let tintView = UIView()
    tintView.backgroundColor = UIColor(tint)
    tintView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
    view.contentView.addSubview(tintView)

    return view
  }

  public func updateUIView(_ uiView: UIVisualEffectView, context: Context) {
    uiView.effect = UIBlurEffect(style: style)
    uiView.layer.cornerRadius = cornerRadius
  }
}

