// MARK: - View Modifier

extension View {
  /// Presents the system share sheet.
  ///
  /// ```swift
  /// view.shareSheet(isPresented: $sharing, items: [videoURL, "Check out my clip!"])
  /// ```
  public func shareSheet(
    isPresented: Binding<Bool>,
    items: [Any],
    onDismiss: (() -> Void)? = nil
